def append_to_csv(filepath: str, rows: list):
    path = Path(filepath)
    existing = []
    if path.exists():
        with open(filepath, 'r', encoding='utf-8') as f:
            reader = csv.reader(f)
            existing = list(reader)

    with open(filepath, 'a', newline='', encoding='utf-8') as f:
        writer = csv.writer(f)
        if not existing:
            writer.writerow(['知识类型', '描述', '来源', '标签', '质量'])
        writer.writerows(rows)

    print(f"[+{len(rows)}] {filepath}")


# strategy 的 knowledge_strategy.csv 是新文件
for filepath, rows in BATCHES.items():
    append_to_csv(filepath, rows)

# 统计
total = sum(len(v) for v in BATCHES.values())
print(f"\n总计追加 {total} 条知识条目")
